import boto3
import os
import re
from flask import Flask, request, jsonify
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from urllib.parse import urlparse

app = Flask(__name__)

# AWS S3 configuration
S3_BUCKET = 'your-s3-bucket-name'
s3_client = boto3.client('s3')

# Chrome WebDriver configuration
CHROME_DRIVER_PATH = '/path/to/chromedriver'
CHROME_OPTIONS = Options()
CHROME_OPTIONS.add_argument('--headless')
CHROME_OPTIONS.add_argument('--no-sandbox')
CHROME_OPTIONS.add_argument('--disable-dev-shm-usage')

# Validate URL
def is_valid_url(url):
    parsed_url = urlparse(url)
    if not parsed_url.scheme or not parsed_url.netloc:
        return False
    if re.match(r'^(localhost|127\.0\.0\.1|::1)', parsed_url.netloc):
        return False
    return True

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url or not is_valid_url(url):
        return jsonify({'error': 'Invalid URL'}), 400

    try:
        # Initialize WebDriver
        driver = webdriver.Chrome(executable_path=CHROME_DRIVER_PATH, options=CHROME_OPTIONS)
        driver.set_page_load_timeout(30)
        driver.get(url)

        # Take screenshot
        screenshot_data = driver.get_screenshot_as_png()
        driver.quit()

        # Save to S3
        file_name = f'screenshots/{os.path.basename(urlparse(url).path)}.png'
        s3_client.put_object(Bucket=S3_BUCKET, Key=file_name, Body=screenshot_data, ContentType='image/png')

        # Return S3 URL
        s3_url = f'https://{S3_BUCKET}.s3.amazonaws.com/{file_name}'
        return jsonify({'screenshot_url': s3_url})

    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

# Note: Ensure that the EC2 instance has the necessary IAM role with S3 write permissions.